async function main() {
  await mongoose.connect(MONGO_URI);
  console.log('connected');

  const exam = await Exam.findOne({ code: 'CTET' });
  if (!exam) { console.error('Exam CTET not found'); process.exit(1); }

  const PATTERN_TITLE = "Paper-II (Social Studies/Social Science)";
  let pattern = await ExamPattern.findOne({ exam: exam._id, title: PATTERN_TITLE });
  if (!pattern) {
    pattern = await ExamPattern.create({
      exam: exam._id, title: PATTERN_TITLE,
      duration: 150, totalMarks: 150, negativeMarking: 0,
      sections: [
        { name: "Child Development and Pedagogy", totalQuestions: 30, marksPerQuestion: 1, negativePerQuestion: 0 },
        { name: "Social Studies / Social Science", totalQuestions: 60, marksPerQuestion: 1, negativePerQuestion: 0 },
        { name: "Language I (English)", totalQuestions: 30, marksPerQuestion: 1, negativePerQuestion: 0 },
        { name: "Language II (English)", totalQuestions: 30, marksPerQuestion: 1, negativePerQuestion: 0 },
      ],
    });
    console.log('created ExamPattern', String(pattern._id));
  } else {
    console.log('reusing ExamPattern', String(pattern._id));
  }

  const title = "CTET Paper-II (Social Studies/Social Science) - 31 January 2021";
  const slug = slugify(title);
  const exists = await PracticeTest.findOne({ slug });
  if (exists) { console.log('PracticeTest already exists', String(exists._id), '- skipping'); await mongoose.disconnect(); return; }

  const questions = RAW.map(r => ({
    questionText: r.q, questionImage: '',
    options: r.o, optionImages: [],
    correctAnswerIndex: r.a, explanation: '', explanationImage: '',
    section: r.s, tags: TAGS, difficulty: 'medium',
  }));
  if (questions.length !== 150) { console.error('expected 150, got', questions.length); process.exit(1); }

  const doc = await PracticeTest.create({
    examPattern: pattern._id, title, slug,
    totalMarks: 150, duration: 150, accessLevel: 'FREE',
    isPYQ: true, pyqYear: 2021, pyqShift: null,
    pyqExamName: "CTET Paper-II (Social Studies/Social Science)",
    questions,
  });
  console.log('created PracticeTest', String(doc._id), '-', questions.length, 'questions');
  await mongoose.disconnect();
  console.log('done');
}
main().catch(e => { console.error(e); process.exit(1); });
